    "public int translate(CharSequence input, int index, Writer out) throws IOException {
        int seqEnd = input.length();
        // Uses -2 to ensure there is something after the &#
        if (input.charAt(index) == '&' && index < seqEnd - 1 && input.charAt(index + 1) == '#') {
            int start = index + 2;
            boolean isHex = false;

            if (start >= seqEnd) {
                // Nothing after '&#'
                return 0;
            }

            char firstChar = input.charAt(start);
            if (firstChar == 'x' || firstChar == 'X') {
                start++;
                isHex = true;
                if (start >= seqEnd) {
                    // '&#x' with nothing after
                    return 0;
                }
            }

            int end = start;
            boolean hasDigits = false;
            boolean hasSemicolon = false;

            while (end < seqEnd) {
                char c = input.charAt(end);
                if (c == ';') {
                    hasSemicolon = true;
                    break;
                }
                if (isHex ? (('0' <= c && c <= '9') || ('a' <= c && c <= 'f') || ('A' <= c && c <= 'F')) : Character.isDigit(c)) {
                    hasDigits = true;
                    end++;
                    continue;
                }
                break; // Non-digit terminates the number (unfinished entity supported)
            }

            if (!hasDigits) {
                // Not a valid numeric entity
                return 0;
            }

            int entityValue;
            try {
                if (isHex) {
                    entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 16);
                } else {
                    entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 10);
                }
            } catch (NumberFormatException nfe) {
                return 0;
            }

            if (entityValue > 0xFFFF) {
                char[] chrs = Character.toChars(entityValue);
                out.write(chrs[0]);
                out.write(chrs[1]);
            } else {
                out.write(entityValue);
            }

            return 2 + (isHex ? 1 : 0) + (end - start) + (hasSemicolon ? 1 : 0);
        }
        return 0;
    }"
